@namespace sv_2fdc76dfa1be4326b371d118e3613923.Components.JobApplication

<nav class="step-indicator mb-4" aria-label="Application progress">
    <ol class="step-list">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var status = GetStepStatus(stepIndex);
            <li class="step-item @status"
                role="listitem"
                @onclick="() => HandleStepClick(stepIndex)">
                <span class="step-circle">
                    @if (status == "completed")
                    {
                        <span class="step-check">&#10003;</span>
                    }
                    else
                    {
                        @(stepIndex + 1)
                    }
                </span>
                <span class="step-label">@StepNames[stepIndex]</span>
            </li>
            @if (stepIndex < StepNames.Length - 1)
            {
                <li class="step-connector @(stepIndex < CurrentStep ? "completed" : "")" aria-hidden="true"></li>
            }
        }
    </ol>
</nav>

@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public HashSet<int> CompletedSteps { get; set; } = new();
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string GetStepStatus(int step)
    {
        if (step == CurrentStep) return "active";
        if (CompletedSteps.Contains(step)) return "completed";
        return "dimmed";
    }

    private async Task HandleStepClick(int step)
    {
        if (CompletedSteps.Contains(step))
        {
            await OnStepClicked.InvokeAsync(step);
        }
    }
}

.step-indicator {
    width: 100%;
}

.step-list {
    display: flex;
    align-items: center;
    list-style: none;
    padding: 0;
    margin: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    flex-shrink: 0;
}

.step-connector {
    flex: 1;
    height: 2px;
    background-color: #dee2e6;
    margin: 0 0.25rem;
    align-self: center;
    margin-bottom: 1.25rem;
    min-width: 1.5rem;
    list-style: none;
}

.step-connector.completed {
    background-color: #198754;
}

.step-circle {
    width: 2.25rem;
    height: 2.25rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.35rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s ease;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #adb5bd;
    white-space: nowrap;
