toolArgs.file_text:
.step-indicator {
    width: 100%;
}

.step-list {
    display: flex;
    align-items: center;
    list-style: none;
    padding: 0;
    margin: 0;
}

.step-item {
    display: flex;
    flex-direction: column;
    align-items: center;
    position: relative;
    flex-shrink: 0;
}

.step-connector {
    flex: 1;
    height: 2px;
    background-color: #dee2e6;
    margin: 0 0.25rem;
    align-self: center;
    margin-bottom: 1.25rem;
    min-width: 1.5rem;
    list-style: none;
}

.step-connector.completed {
    background-color: #198754;
}

.step-circle {
    width: 2.25rem;
    height: 2.25rem;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: 600;
    font-size: 0.875rem;
    margin-bottom: 0.35rem;
    border: 2px solid #dee2e6;
    background: #fff;
    color: #adb5bd;
    transition: all 0.2s ease;
}

.step-label {
    font-size: 0.75rem;
    text-align: center;
    color: #adb5bd;
    white-space: nowrap;
    transition: color 0.2s ease;
}

.step-item.active .step-circle {
    border-color: #0d6efd;
    background-color: #0d6efd;
    color: #fff;
}

.step-item.active .step-label {
    color: #0d6efd;
    font-weight: 600;
}

.step-item.completed {
    cursor: pointer;
}

.step-item.completed .step-circle {
    border-color: #198754;
    background-color: #198754;
    color: #fff;
}

.step-item.completed .step-label {
    color: #198754;
}

.step-item.completed:hover .step-circle {
    background-color: #157347;
    border-color: #157347;
}

.step-check {
    font-size: 1rem;
    line-height: 1;
}

.step-item.dimmed {
    pointer-events: none;
}

