@namespace sv_2fdc76dfa1be4326b371d118e3613923.Components.JobApplication

<h5 class="mb-3">Cover Letter</h5>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="CoverLetter" @bind:event="oninput"
              placeholder="Tell us why you're a great fit for this position..."
              maxlength="@MaxLength"></textarea>
    <div class="form-text text-end">
        <span class="@(CoverLetter.Length > MaxLength ? "text-danger" : "")">
            @CoverLetter.Length / @MaxLength characters
        </span>
    </div>
</div>

<div class="d-flex justify-content-between mt-3">
    <button class="btn btn-outline-secondary" @onclick="HandleBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    private const int MaxLength = 2000;

    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnCompleted { get; set; }

    private async Task HandleBack() => await OnBack.InvokeAsync();

    private async Task HandleNext() => await OnCompleted.InvokeAsync();
}

@namespace sv_2fdc76dfa1be4326b371d118e3613923.Components.JobApplication
@using sv_2fdc76dfa1be4326b371d118e3613923.Models

<h5 class="mb-4">Review Your Application</h5>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Personal Information</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
    </div>
    <div class="card-body">
        <div class="row">
            <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
            <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
            <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
            <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
        </div>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Work History</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var entry in WorkEntries)
        {
            <div class="mb-3 pb-3 border-bottom last-child-no-border">
                <div><strong>@entry.Title</strong> at @entry.Company</div>
                <div class="text-muted small">
                    @entry.StartDate?.ToString("MMM yyyy") &ndash;
                    @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                </div>
                @if (!string.IsNullOrWhiteSpace(entry.Description))
                {
                    <div class="mt-1">@entry.Description</div>
                }
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>References</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
    </div>
    <div class="card-body">
        @foreach (var r in References)
        {
            <div class="mb-2">
                <strong>@r.Name</strong> (@r.Relationship)<br />
                <span class="text-muted">@r.Email &bull; @r.Phone</span>
            </div>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header d-flex justify-content-between align-items-center">
        <strong>Cover Letter</strong>
        <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
    </div>
    <div class="card-body">
        <p style="white-space: pre-wrap;">@CoverLetter</p>
    </div>
</div>

@if (!string.IsNullOrEmpty(_errorMessage))
{
    <div class="alert alert-danger">@_errorMessage</div>
}

<div class="d-flex justify-content-between mt-4">
    <button class="btn btn-outline-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@_submitting">
        @if (_submitting)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
        }
        Submit Application
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool _submitting;
    private string? _errorMessage;

    private async Task HandleSubmit()
    {
        _submitting = true;
        _errorMessage = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            _errorMessage = $"Submission failed: {ex.Message}";
        }
        finally
        {
            _submitting = false;
        }
    }
}

