@page "/apply"
@using sv_2fdc76dfa1be4326b371d118e3613923.Components.JobApplication
@using sv_2fdc76dfa1be4326b371d118e3613923.Models
@using sv_2fdc76dfa1be4326b371d118e3613923.Services
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h3 class="mb-4">Job Application</h3>

    @if (_submittedId.HasValue)
    {
        <div class="text-center py-5">
            <div class="mb-3">
                <span style="font-size: 3rem; color: #198754;">&#10003;</span>
            </div>
            <h4 class="text-success">Application Submitted!</h4>
            <p class="text-muted">Your application ID is:</p>
            <h2 class="fw-bold">@_submittedId</h2>
            <p class="text-muted mt-3">We'll be in touch soon. Thank you for applying!</p>
        </div>
    }
    else
